import os
import sys
import argparse

def create_archive(directory, compression_format):
    """Create a compressed archive of the specified directory using the desired compression format."""
    # Check if the directory exists
    if not os.path.isdir(directory):
        raise ValueError("Directory does not exist: " + directory)
    
    # Create the archive name based on the directory and compression format
    archive_name = directory + "." + compression_format
    
    # Create the archive using the appropriate library function
    if compression_format == "tar.gz":
        import tarfile
        with tarfile.open(archive_name, "w:gz") as tar:
            tar.add(directory)
    elif compression_format == "tar.bz2":
        import tarfile
        with tarfile.open(archive_name, "w:bz2") as tar:
            tar.add(directory)
    elif compression_format == "zip":
        import zipfile
        with zipfile.ZipFile(archive_name, "w", compression=zipfile.ZIP_DEFLATED) as zip:
            zip.write(directory)
    elif compression_format == "7z":
        import subprocess
        # Use the 7-Zip command line tool to create the archive
        cmd = ["7za", "a", "-tzip", archive_name, directory]
        subprocess.call(cmd)
    else:
        raise ValueError("Unsupported compression format: " + compression_format)
    
    # Return the name of the created archive
    return archive_name

# Parse command line arguments
parser = argparse.ArgumentParser()
parser.add_argument("directory", help="path to directory to be backed up")
parser.add_argument("compression_format", choices=["tar.gz", "tar.bz2", "zip", "7z"], help="compression format to use for the archive")
args = parser.parse_args()

# Call the create_archive function with the specified directory and compression format
create_archive(args.directory, args.compression_format)